import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

export default function RegisterPage() {
  const [formData, setFormData] = useState({
    email: '',
    first_name: '',
    last_name: '',
    password: ''
  });
  const { register, error } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const success = await register(formData);
    if (success) {
      navigate('/login');
    }
  };

  return (
    <div style={styles.container}>
      <form onSubmit={handleSubmit} style={styles.form}>
        <h2 style={styles.title}>📝 Регистрация</h2>
        
        {error && <div style={styles.error}>{error}</div>}
        
        <div style={styles.field}>
          <label>Email:</label>
          <input
            type="email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            required
            style={styles.input}
          />
        </div>
        
        <div style={styles.field}>
          <label>Имя:</label>
          <input
            type="text"
            name="first_name"
            value={formData.first_name}
            onChange={handleChange}
            required
            style={styles.input}
          />
        </div>
        
        <div style={styles.field}>
          <label>Фамилия:</label>
          <input
            type="text"
            name="last_name"
            value={formData.last_name}
            onChange={handleChange}
            required
            style={styles.input}
          />
        </div>
        
        <div style={styles.field}>
          <label>Пароль:</label>
          <input
            type="password"
            name="password"
            value={formData.password}
            onChange={handleChange}
            required
            style={styles.input}
          />
        </div>
        
        <button type="submit" style={styles.button}>Зарегистрироваться</button>
        
        <p style={styles.link}>
          Уже есть аккаунт? <a href="/login">Войти</a>
        </p>
      </form>
    </div>
  );
}

const styles = {
  container: { maxWidth: '400px', margin: '50px auto', padding: '20px' },
  form: { background: '#1a1f2e', padding: '30px', borderRadius: '12px' },
  title: { color: '#4ade80', marginBottom: '20px', textAlign: 'center' },
  field: { marginBottom: '15px' },
  input: { width: '100%', padding: '10px', background: '#2a2f3e', border: '1px solid #333', color: 'white', borderRadius: '6px' },
  button: { width: '100%', padding: '12px', background: '#4ade80', color: '#0b0f19', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold' },
  error: { background: '#ff4444', color: 'white', padding: '10px', borderRadius: '6px', marginBottom: '20px' },
  link: { textAlign: 'center', marginTop: '20px', color: '#888' }
};
